// 1. Retrieve items
const allItems = $input.all();

// 2. Merge texts
let mergedText = allItems
  .map(item => item.json.output) 
  .join('\n\n---\n\n'); 

// 3. Check length
const MAX_LENGTH = 1800;

if (mergedText && mergedText.length > MAX_LENGTH) {
  // Cut 1800 characters 
  let trimmed = mergedText.substring(0, MAX_LENGTH);


  const lastDotIndex = trimmed.lastIndexOf('.');
  if (lastDotIndex > 0) {
    trimmed = trimmed.substring(0, lastDotIndex + 1);
  }

  mergedText = trimmed + "\n\n(Testo troncato per limiti di lunghezza...)";
}

// 4. Result
return { json: { final_summary: mergedText } };
